        if (element_idx < size) {
            T x = input[element_idx];
            output[element_idx] = selu_compute(x);
        }
    }
}

// Specialized kernel for float32 with warp-level optimization
__global__ void selu_kernel_float32(const float* __restrict__ input, float* __restrict__ output, int64_t size) {
    const int64_t idx = (blockIdx.x * blockDim.x + threadIdx.x);

    // Process VECTOR_SIZE_FLOAT4 elements per thread with vectorized loads/stores
    const int64_t vectorized_idx = idx * VECTOR_SIZE_FLOAT4;
    if (vectorized_idx + VECTOR_SIZE_FLOAT4 - 1 < size) {
        // Load VECTOR_SIZE_FLOAT4 floats at once
        float4 in = *reinterpret_cast<const float4*>(&input[vectorized_idx]);

        // Compute SELU
